    { name: 'Completed', value: (stats as any).completedResponses },
    { name: 'In Progress', value: (stats as any).inProgressResponses },
  ] : [];

  return (
    <div className="min-h-screen bg-[#F5F5F5] dark:bg-[#1E1E1E]">
      {/* Power BI-style Header */}
