              data-testid="img-logo"
            />
            <div className="h-8 w-px bg-gray-200 dark:bg-gray-700" />
            <h1 className="text-base font-semibold text-gray-900 dark:text-gray-100">Survey Analytics Dashboard</h1>
          </div>
          <ThemeToggle />
        </div>
