import type { Express, Request, Response, NextFunction } from "express";
import { createServer, type Server } from "http";
import { storage } from "./storage";
import type { SurveyAnswers, HRAccount } from "@shared/schema";
import { saveSurveySchema, submitSurveySchema } from "@shared/surveyValidation";
import { emailSchema, loginSchema } from "@shared/schema";
import { fromError } from "zod-validation-error";

// Extend Express Request to include HR account info
declare global {
  namespace Express {
    interface Request {
      hrAccount?: HRAccount;
      userEmail?: string;
    }
  }
}

// Simple middleware to validate email in request body
const validateEmail = (req: Request, res: Response, next: NextFunction) => {
  const email = req.body.email || req.query.email;

  if (!email) {
    return res.status(400).json({ message: "Email is required" });
  }

  const result = emailSchema.safeParse(email);
  if (!result.success) {
    const validationError = fromError(result.error);
    return res.status(400).json({ 
      message: validationError.message || "Invalid email format. Please use your corporate email address.",
      error: validationError.toString() 
    });
  }

  // Attach validated email to request
  req.userEmail = result.data;
  next();
};

// HR authentication middleware
const requireHRAuth = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const token = req.cookies?.hr_session;

    if (!token) {
      return res.status(401).json({ message: "Not authenticated" });
    }

    const session = await storage.getSession(token);
    if (!session) {
      return res.status(401).json({ message: "Invalid or expired session" });
    }

    const account = await storage.getHRAccountById(session.hrAccountId);
    if (!account) {
      return res.status(401).json({ message: "Account not found" });
    }

    req.hrAccount = account;
    next();
  } catch (error) {
    console.error("Auth middleware error:", error);
    res.status(500).json({ message: "Authentication error" });
  }
};

export async function registerRoutes(app: Express): Promise<Server> {
  // HR Authentication routes
  app.post("/api/hr/login", async (req, res) => {
    try {
      const result = loginSchema.safeParse(req.body);
      if (!result.success) {
        return res.status(400).json({ message: "Invalid login credentials" });
      }

      const { email, password } = result.data;
      const hrAccount = await storage.validateHRCredentials(email, password);

      if (!hrAccount) {
        return res.status(401).json({ message: "Invalid email or password" });
      }

      // Create session
      const session = await storage.createSession(hrAccount.id);
      await storage.updateLastLogin(hrAccount.id);

      // Set HTTP-only cookie
      res.cookie("hr_session", session.token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === "production",
        sameSite: "lax",
        path: "/",
        maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
      });

      res.json({
        success: true,
        account: {
          id: hrAccount.id,
          email: hrAccount.email,
          role: hrAccount.role,
          companyId: hrAccount.companyId,
        },
      });
    } catch (error) {
      console.error("Login error:", error);
      res.status(500).json({ message: "Login failed" });
    }
  });

  app.post("/api/hr/logout", requireHRAuth, async (req, res) => {
    try {
      const token = req.cookies?.hr_session;
      if (token) {
        await storage.deleteSession(token);
      }
      res.clearCookie("hr_session", { path: "/" });
      res.json({ success: true });
    } catch (error) {
      console.error("Logout error:", error);
      res.status(500).json({ message: "Logout failed" });
    }
  });

  app.get("/api/hr/me", requireHRAuth, async (req, res) => {
    try {
      if (!req.hrAccount) {
        return res.status(401).json({ message: "Not authenticated" });
      }

      res.json({
        id: req.hrAccount.id,
        email: req.hrAccount.email,
        role: req.hrAccount.role,
        companyId: req.hrAccount.companyId,
      });
    } catch (error) {
      console.error("Error fetching HR account:", error);
      res.status(500).json({ message: "Failed to fetch account" });
    }
  });

  // Auth routes - simple email validation
  app.post('/api/auth/validate', async (req: any, res) => {
    try {
      // Validate email from request body
      const result = emailSchema.safeParse(req.body.email);
      if (!result.success) {
        const validationError = fromError(result.error);
        return res.status(400).json({ 
          message: validationError.message || "Invalid email format. Please use your corporate email address.",
          error: validationError.toString() 
        });
      }

      const email = result.data;

      // Create or update user with demographic information
      const user = await storage.upsertUser({
        email,
        firstName: req.body.firstName,
        lastName: req.body.lastName,
        department: req.body.department,
        educationLevel: req.body.educationLevel,
        gender: req.body.gender,
        workingTenure: req.body.workingTenure,
      });

      res.json({ user, email });
    } catch (error) {
      console.error("Error validating email:", error);
      res.status(500).json({ message: "Failed to validate email" });
    }
  });

  app.get('/api/auth/user', validateEmail, async (req: any, res) => {
    try {
      const email = req.userEmail;
      const user = await storage.getUser(email);

      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }

      res.json(user);
    } catch (error) {
      console.error("Error fetching user:", error);
      res.status(500).json({ message: "Failed to fetch user" });
    }
  });

  // Survey routes
  app.get("/api/survey/response", validateEmail, async (req: any, res) => {
    try {
      const email = req.userEmail;
      const response = await storage.getSurveyResponse(email);

      if (!response) {
        return res.json(null);
      }

      res.json(response);
    } catch (error) {
      console.error("Error fetching survey response:", error);
      res.status(500).json({ message: "Failed to fetch survey response" });
    }
  });

  app.post("/api/survey/save", validateEmail, async (req: any, res) => {
    try {
      const email = req.userEmail;

      // Extract email from body before validation (injected by queryClient)
      const { email: _, ...bodyWithoutEmail } = req.body;

      // Validate request body with Zod
      const validationResult = saveSurveySchema.safeParse(bodyWithoutEmail);
      if (!validationResult.success) {
        const validationError = fromError(validationResult.error);
        return res.status(400).json({ 
          message: "Invalid request data", 
          error: validationError.toString() 
        });
      }

      const { answers, isComplete } = validationResult.data;
      const response = await storage.saveSurveyResponse(email, answers as SurveyAnswers, isComplete);
      res.json(response);
    } catch (error) {
      console.error("Error saving survey response:", error);
      res.status(500).json({ message: "Failed to save survey response" });
    }
  });

  app.post("/api/survey/submit", validateEmail, async (req: any, res) => {
    try {
      const email = req.userEmail;

      // Extract email from body before validation (injected by queryClient)
      const { email: _, ...bodyWithoutEmail } = req.body;

      // Validate request body with Zod - ensures all 50 questions answered
      const validationResult = submitSurveySchema.safeParse(bodyWithoutEmail);
      if (!validationResult.success) {
        const validationError = fromError(validationResult.error);
        return res.status(400).json({ 
          message: "Invalid or incomplete survey data", 
          error: validationError.toString() 
        });
      }

      const { answers } = validationResult.data;
      const response = await storage.submitSurveyResponse(email, answers as SurveyAnswers);
      res.json(response);
    } catch (error) {
      console.error("Error submitting survey response:", error);
      res.status(500).json({ message: "Failed to submit survey response" });
    }
  });

  // Dashboard routes (protected for HR/Admin)
  app.get("/api/dashboard/stats", requireHRAuth, async (req, res) => {
    try {
      // HR can only see their company's data, admin can see all
      const companyId = req.hrAccount?.role === "admin" ? undefined : req.hrAccount?.companyId;
      const stats = await storage.getSurveyStats(companyId);
      res.json(stats);
    } catch (error) {
      console.error("Error fetching dashboard stats:", error);
      res.status(500).json({ message: "Failed to fetch dashboard stats" });
    }
  });

  app.get("/api/dashboard/section-averages", requireHRAuth, async (req, res) => {
    try {
      const companyId = req.hrAccount?.role === "admin" ? undefined : req.hrAccount?.companyId;
      const averages = await storage.getSectionAverages(companyId);
      res.json(averages);
    } catch (error) {
      console.error("Error fetching section averages:", error);
      res.status(500).json({ message: "Failed to fetch section averages" });
    }
  });

  app.get("/api/dashboard/responses", requireHRAuth, async (req, res) => {
    try {
      const companyId = req.hrAccount?.role === "admin" ? undefined : req.hrAccount?.companyId;
      const responses = await storage.getAllSurveyResponses(companyId);
      res.json(responses);
    } catch (error) {
      console.error("Error fetching survey responses:", error);
      res.status(500).json({ message: "Failed to fetch survey responses" });
    }
  });

  app.get("/api/dashboard/company-insights", requireHRAuth, async (req, res) => {
    try {
      const companyId = req.hrAccount?.role === "admin" ? undefined : req.hrAccount?.companyId;
      const insights = await storage.getCompanyInsights(companyId);
      res.json(insights);
    } catch (error) {
      console.error("Error fetching company insights:", error);
      res.status(500).json({ message: "Failed to fetch company insights" });
    }
  });

  // Individual responses endpoint (ADMIN ONLY - HR should not see detailed answers)
  app.get("/api/dashboard/responses-with-users", requireHRAuth, async (req, res) => {
    try {
      // Only admins can view individual detailed responses
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const responses = await storage.getResponsesWithUsers();
      res.json(responses);
    } catch (error) {
      console.error("Error fetching responses with users:", error);
      res.status(500).json({ message: "Failed to fetch responses with users" });
    }
  });

  // Individual response detail endpoint (ADMIN ONLY - HR should not see detailed answers)
  app.get("/api/dashboard/response/:responseNumber", requireHRAuth, async (req, res) => {
    try {
      // Only admins can view individual detailed responses
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const responseNumber = parseInt(req.params.responseNumber);
      if (isNaN(responseNumber)) {
        return res.status(400).json({ message: "Invalid response number" });
      }

      const response = await storage.getResponseByNumber(responseNumber);
      if (!response) {
        return res.status(404).json({ message: "Response not found" });
      }

      res.json(response);
    } catch (error) {
      console.error("Error fetching response by number:", error);
      res.status(500).json({ message: "Failed to fetch response" });
    }
  });

  app.get("/api/dashboard/wellbeing-metrics", requireHRAuth, async (req, res) => {
    try {
      const companyId = req.hrAccount?.role === "admin" ? undefined : req.hrAccount?.companyId;
      const filters = {
        department: req.query.department as string | undefined,
        educationLevel: req.query.educationLevel as string | undefined,
        gender: req.query.gender as string | undefined,
        workingTenure: req.query.workingTenure as string | undefined,
        companyDomain: req.query.companyDomain as string | undefined,
        companyId,
      };

      const metrics = await storage.getWellbeingMetrics(filters);
      res.json(metrics);
    } catch (error) {
      console.error("Error fetching wellbeing metrics:", error);
      res.status(500).json({ message: "Failed to fetch wellbeing metrics" });
    }
  });

  app.get("/api/dashboard/demographic-breakdown", requireHRAuth, async (req, res) => {
    try {
      const companyId = req.hrAccount?.role === "admin" ? undefined : req.hrAccount?.companyId;
      const breakdown = await storage.getDemographicBreakdown(companyId);
      res.json(breakdown);
    } catch (error) {
      console.error("Error fetching demographic breakdown:", error);
      res.status(500).json({ message: "Failed to fetch demographic breakdown" });
    }
  });

  // HR Accounts route (admin only)
  app.get("/api/dashboard/hr-accounts", requireHRAuth, async (req, res) => {
    try {
      // Only admins can view all HR accounts
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const accounts = await storage.getAllHRAccounts();

      // Remove sensitive data before sending
      const sanitized = accounts.map(({ passwordHash, ...account }) => ({
        ...account,
        // Don't include password hash in response
      }));

      res.json(sanitized);
    } catch (error) {
      console.error("Error fetching HR accounts:", error);
      res.status(500).json({ message: "Failed to fetch HR accounts" });
    }
  });

  // Export route for CSV download (ADMIN ONLY - contains individual response data)
  app.get("/api/dashboard/export-csv", requireHRAuth, async (req, res) => {
    try {
      // Only admins can export individual response data
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const responses = await storage.getResponsesWithUsers();

      // Build CSV header
      let csv = "Response Number,Email,First Name,Last Name,Department,Education Level,Gender,Working Tenure,Completed At,Section A Avg,Section B Avg,Section C Avg,Section D Avg,Section E Avg\n";

      // Process each response
      responses.forEach((response) => {
        const answers = response.answers as SurveyAnswers;
        const answerValues: Record<string, number> = {
          'strongly_disagree': 1,
          'disagree': 2,
          'neutral': 3,
          'agree': 4,
          'strongly_agree': 5,
        };

        // Calculate section averages for this response
        const calcSectionAvg = (start: number, end: number) => {
          let sum = 0;
          let count = 0;
          for (let i = start; i <= end; i++) {
            const answer = answers[i.toString()];
            if (answer) {
              sum += answerValues[answer] || 0;
              count++;
            }
          }
          return count > 0 ? (sum / count).toFixed(2) : "0";
        };

        const sectionA = calcSectionAvg(1, 10);
        const sectionB = calcSectionAvg(11, 20);
        const sectionC = calcSectionAvg(21, 30);
        const sectionD = calcSectionAvg(31, 40);
        const sectionE = calcSectionAvg(41, 50);

        // Escape CSV values
        const escape = (val: string | null | undefined) => {
          if (!val) return "";
          return `"${val.replace(/"/g, '""')}"`;
        };

        csv += `${response.responseNumber},${escape(response.user.email)},${escape(response.user.firstName)},${escape(response.user.lastName)},${escape(response.user.department)},${escape(response.user.educationLevel)},${escape(response.user.gender)},${escape(response.user.workingTenure)},${response.completedAt?.toISOString() || ""},${sectionA},${sectionB},${sectionC},${sectionD},${sectionE}\n`;
      });

      // Set headers for file download
      res.setHeader('Content-Type', 'text/csv');
      res.setHeader('Content-Disposition', `attachment; filename="survey-responses-${new Date().toISOString().split('T')[0]}.csv"`);
      res.send(csv);
    } catch (error) {
      console.error("Error exporting CSV:", error);
      res.status(500).json({ message: "Failed to export data" });
    }
  });

  // Admin-only routes
  app.get("/api/admin/companies", requireHRAuth, async (req, res) => {
    try {
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }
      const companies = await storage.getAllCompanies();
      res.json(companies);
    } catch (error) {
      console.error("Error fetching companies:", error);
      res.status(500).json({ message: "Failed to fetch companies" });
    }
  });

  app.get("/api/admin/employees", requireHRAuth, async (req, res) => {
    try {
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }
      const companyId = req.query.companyId ? parseInt(req.query.companyId as string) : undefined;
      const employees = await storage.getAllEmployees(companyId);
      res.json(employees);
    } catch (error) {
      console.error("Error fetching employees:", error);
      res.status(500).json({ message: "Failed to fetch employees" });
    }
  });

  // Certification routes (admin only)
  app.post("/api/admin/certifications", requireHRAuth, async (req, res) => {
    try {
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const { companyId, title, description, validUntil } = req.body;

      if (!companyId || !title) {
        return res.status(400).json({ message: "Company ID and title are required" });
      }

      // Generate unique certificate number
      const certificateNumber = `CERT-${Date.now()}-${Math.random().toString(36).substring(2, 9).toUpperCase()}`;

      const certification = await storage.createCertification({
        companyId,
        certificateNumber,
        issuedBy: req.hrAccount.id,
        title,
        description,
        validUntil: validUntil ? new Date(validUntil) : undefined,
      });

      res.json(certification);
    } catch (error) {
      console.error("Error creating certification:", error);
      res.status(500).json({ message: "Failed to create certification" });
    }
  });

  app.get("/api/admin/certifications", requireHRAuth, async (req, res) => {
    try {
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const companyId = req.query.companyId ? parseInt(req.query.companyId as string) : undefined;
      const certifications = await storage.getAllCertifications(companyId);
      res.json(certifications);
    } catch (error) {
      console.error("Error fetching certifications:", error);
      res.status(500).json({ message: "Failed to fetch certifications" });
    }
  });

  app.patch("/api/admin/certifications/:id/revoke", requireHRAuth, async (req, res) => {
    try {
      if (req.hrAccount?.role !== "admin") {
        return res.status(403).json({ message: "Access denied. Admin only." });
      }

      const id = parseInt(req.params.id);
      await storage.revokeCertification(id);
      res.json({ success: true });
    } catch (error) {
      console.error("Error revoking certification:", error);
      res.status(500).json({ message: "Failed to revoke certification" });
    }
  });

  const httpServer = createServer(app);
  return httpServer;
}

