import { useQuery } from "@tanstack/react-query";

interface HRAccount {
  id: number;
  email: string;
  role: string;
  companyId: number;
}

export function useHRAuth() {
  const { data: hrAccount, isLoading, error } = useQuery<HRAccount>({
    queryKey: ["/api/hr/me"],
    retry: false,
  });

  return {
    hrAccount,
    isAuthenticated: !!hrAccount && !error,
    isLoading,
    isAdmin: hrAccount?.role === "admin",
  };
}

client/src/pages/hr-login.tsx.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { AlertCircle } from "lucide-react";

export default function HRLogin() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const loginMutation = useMutation({
    mutationFn: async (credentials: { email: string; password: string }) => {
      return apiRequest("POST", "/api/hr/login", credentials);
    },
    onSuccess: (data: any) => {
      toast({
        title: "Login successful",
        description: "Redirecting to dashboard...",
      });
      // Redirect admin to /dashboard, HR to /hr-dashboard
      if (data.account?.role === "admin") {
        setLocation("/dashboard");
      } else {
        setLocation("/hr-dashboard");
      }
    },
    onError: (error: any) => {
      toast({
        title: "Login failed",
        description: error.message || "Invalid email or password",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) {
      toast({
        title: "Missing credentials",
        description: "Please enter both email and password",
        variant: "destructive",
      });
      return;
    }
    loginMutation.mutate({ email, password });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <Card className="w-full max-w-md">
        <CardHeader className="space-y-1">
          <CardTitle className="text-2xl font-bold">HR Portal Login</CardTitle>
          <CardDescription>
            Sign in to access your company's survey analytics
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="email" data-testid="label-email">
                Email
              </Label>
              <Input
                id="email"
                type="email"
                placeholder="hr@company.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                disabled={loginMutation.isPending}
                data-testid="input-email"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password" data-testid="label-password">
                Password
              </Label>
              <Input
                id="password"
                type="password"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                disabled={loginMutation.isPending}
                data-testid="input-password"
              />
            </div>

            <div className="rounded-md bg-muted p-3 text-sm">
              <div className="flex gap-2">
                <AlertCircle className="h-4 w-4 text-muted-foreground mt-0.5" />
                <div className="space-y-1">
                  <p className="font-medium text-foreground">Default Credentials</p>
                  <p className="text-muted-foreground">
                    Admin: admin@admin.com / admin@123
                  </p>
                  <p className="text-muted-foreground">
                    HR: hr@yourcompany.com / 12345678
                  </p>
                  <p className="text-xs text-muted-foreground">
                    HR accounts are auto-created when employees submit surveys
                  </p>
                </div>
              </div>
            </div>

            <Button
              type="submit"
              className="w-full"
              disabled={loginMutation.isPending}
              data-testid="button-login"
            >
              {loginMutation.isPending ? "Signing in..." : "Sign In"}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

